const text = $input.item.json.text || '';
const widthCm = parseInt($input.item.json.width) || 50;
const color = ($input.item.json.color || 'красный').toLowerCase();

const basePrice = widthCm * 120;
const complexityPrice = text.length * 50;

const colorMultipliers = {
  'красный': 1.0, 'red': 1.0,
  'синий': 1.0, 'blue': 1.0,
  'зеленый': 1.0, 'green': 1.0,
  'розовый': 1.1, 'pink': 1.1,
  'белый': 1.15, 'white': 1.15,
  'теплый белый': 1.2, 'warm white': 1.2,
  'rgb': 1.3, 'радужный': 1.3
};

const colorMultiplier = colorMultipliers[color] || 1.0;
const totalPrice = (basePrice + complexityPrice) * colorMultiplier;
const minPrice = Math.round(totalPrice * 0.9 / 100) * 100;
const maxPrice = Math.round(totalPrice * 1.1 / 100) * 100;

const colorName = color.charAt(0).toUpperCase() + color.slice(1);

return {
  json: {
    price_range: `${minPrice.toLocaleString('ru-RU')} - ${maxPrice.toLocaleString('ru-RU')} руб.`,
    details: `Текст: "${text}", Ширина: ${widthCm}см, Цвет: ${colorName}`,
    price_min: minPrice,
    price_max: maxPrice
  }
};
